arguments.file_text:
@using sv_1b86421fdd56470abd31dcbfd1bb7792.Services

<div class="message-item @(IsHighlighted ? "highlighted" : "")"
     @onmouseenter="() => showActions = true"
     @onmouseleave="() => { showActions = false; showEmojiPicker = false; }">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="hover-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool IsHighlighted { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
}

.message-item:hover {
    background: #f8f8f8;
}

.message-item.highlighted {
    background: #fffde7;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #d0d0d0;
    border-radius: 999px;
    background: #f0f0f0;
    font-size: 0.8rem;
    cursor: pointer;
}

.reaction-badge:hover {
    background: #e0e8f0;
    border-color: #1264a3;
}

.thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.hover-actions {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.2rem;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    padding: 0.25rem 0.5rem;
    border: none;
    background: none;
    border-radius: 4px;
    font-size: 0.8rem;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: #e8e8e8;
}

.emoji-picker {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    transform: translateY(-100%);
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 0.4rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 20;
}

.emoji-btn {
    padding: 0.3rem;
    border: none;
    background: none;
    border-radius: 4px;
    font-size: 1.2rem;
    cursor: pointer;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

