arguments.file_text:
@using sv_1b86421fdd56470abd31dcbfd1bb7792.Services

<aside class="channel-sidebar">
    <div class="sidebar-header">
        <h2>Channels</h2>
    </div>
    <nav class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelect="OnChannelSelected" />
        }
    </nav>
</aside>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #e0e0e0;
    border-right: 1px solid #522653;
    overflow: hidden;
}

.sidebar-header {
    padding: 1rem 0.75rem 0.5rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem;
}

@using sv_1b86421fdd56470abd31dcbfd1bb7792.Services

<section class="message-area">
    <header class="area-header">
        <h2># @Channel.Name</h2>
        <span class="header-desc">@Channel.Description</span>
    </header>

    <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
        @if (isLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }
        @if (HasMoreMessages && !isLoadingMore)
        {
            <div class="load-more-hint">Scroll up for older messages</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ReplyCount="GetReplyCount(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                  ButtonLabel="Send"
                  OnSubmit="OnSendMessage" />
</section>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private bool isLoadingMore;

    private int GetReplyCount(int messageId)
        => ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleScroll()
    {
        // JS interop could provide precise scroll position,
        // but we trigger load-more via the OnLoadMore callback.
        // For SSR-friendly approach, we rely on the parent to manage pagination.
    }

    public async Task TriggerLoadMore()
    {
        if (isLoadingMore || !HasMoreMessages) return;
        isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    flex: 1;
    min-width: 0;
    background: #fff;
}

.area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.header-desc {
    font-size: 0.8rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.loading-indicator,
.load-more-hint {
    text-align: center;
    padding: 0.5rem;
    font-size: 0.8rem;
    color: #888;
}

@using sv_1b86421fdd56470abd31dcbfd1bb7792.Services

<aside class="thread-panel">
    <header class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </header>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage" IsHighlighted="true" />
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in ThreadMessages)
            {
                <MessageItem Message="reply"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Reply..."
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    }
</aside>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
