arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_1b86421fdd56470abd31dcbfd1bb7792.Services
@using sv_1b86421fdd56470abd31dcbfd1bb7792.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    @if (currentChannel is not null)
    {
        <MessageArea Channel="currentChannel"
                     Messages="messages"
                     ThreadSummaries="threadSummaries"
                     HasMoreMessages="hasMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadOlderMessages" />
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     ThreadMessages="threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply"
                     OnReact="HandleReaction" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private int selectedChannelId;
    private Channel? currentChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages;
    private int skip;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        currentChannel = channels.FirstOrDefault(c => c.Id == channelId);
        skip = 0;
        messages = [];
        threadSummaries = [];
        CloseThread();

        var loaded = await ChatService.GetMessagesAsync(channelId, skip, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;
        skip = loaded.Count;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update the unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        var older = await ChatService.GetMessagesAsync(selectedChannelId, skip, PageSize);
        hasMoreMessages = older.Count == PageSize;
        messages.InsertRange(0, older);
        skip += older.Count;
        BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            selectedChannelId, content, threadRootMessage.Id);
        threadMessages.Add(reply);

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadMessages.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the message's reactions in the local list
        UpdateReactionInList(messages, args.MessageId, args.Emoji);
        UpdateReactionInList(threadMessages, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
    {
        var idx = list.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = list[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);
        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [..r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        list[idx] = msg with { Reactions = reactions };
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that are reply targets
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);
        threadSummaries = grouped.ToDictionary(
            g => g.Key,
            g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 1.1rem;
    background: #fafafa;
}

